// Define Interface for Source Product in Import Tool
interface SourceProduct {
    id: string;
    name: string;
    sku: string;
    price: number;
    stock: number;
    image: string;
    weight: number;
    description: string;
    status: 'active' | 'inactive';
    existsInOmni: boolean; // Is SKU already in OmniSales?
    isCopied: boolean; // Has been copied in this session?
    variantsCount: number; // Added: Number of variants
}

// Define Interface for Sync History
interface SyncHistoryItem {
    id: string;
    sourceShopName: string;
    targetCount: number;
    timestamp: string;
    status: 'success' | 'failed' | 'partial';
    productsSynced: number;
}

// Define Interface for Import History
interface ImportHistoryItem {
    id: string;
    sourceShopName: string;
    targetWarehouseName: string;
    productCount: number;
    timestamp: string;
    status: 'success' | 'failed';
    details: SourceProduct[]; // Added details to history
}

interface ListingEditData {
    name: string;
    sku: string;
    price: number;
    stock: number;
    description: string;
    weight: number;
    length: number;
    width: number;
    height: number;
    category: string;
    image: string;
    images: string[];
    video: string;
    videoType: 'link' | 'upload';
    attributes: { name: string; value: string }[];
    variants: any[];
    shipping: string[];
}

// --- Component for Step 4 to isolate state and avoid Hook errors ---
const ListingStep4: React.FC<{
  editData: ListingEditData;
  onUpdate: (field: string, value: any) => void;
  onPublish: () => void;
  selectedShopsCount: number;
}> = ({ editData, onUpdate, onPublish, selectedShopsCount }) => {
  // Local State for Variant UI
  const [variantGroup1, setVariantGroup1] = useState({ name: 'Màu sắc', values: [] as string[] });
  const [variantGroup2, setVariantGroup2] = useState({ name: 'Size', values: [] as string[] });
  const [tempVal1, setTempVal1] = useState('');
  const [tempVal2, setTempVal2] = useState('');
  const [bulkPrice, setBulkPrice] = useState<number | ''>('');
  const [bulkStock, setBulkStock] = useState<number | ''>('');

  const handleAddVariantValue = (group: 1 | 2) => {
      if (group === 1 && tempVal1.trim()) {
          setVariantGroup1(prev => ({ ...prev, values: [...prev.values, tempVal1.trim()] }));
          setTempVal1('');
      } else if (group === 2 && tempVal2.trim()) {
          setVariantGroup2(prev => ({ ...prev, values: [...prev.values, tempVal2.trim()] }));
          setTempVal2('');
      }
      // Note: In a real app, this would trigger generating variant combinations in `editData.variants`
  };

  const handleRemoveVariantValue = (group: 1 | 2, val: string) => {
      if (group === 1) setVariantGroup1(prev => ({...prev, values: prev.values.filter(v => v !== val)}));
      else setVariantGroup2(prev => ({...prev, values: prev.values.filter(v => v !== val)}));
  };

  const applyBulkVariant = () => {
      const newVariants = editData.variants.map(v => ({
          ...v,
          price: bulkPrice !== '' ? Number(bulkPrice) : v.price,
          stock: bulkStock !== '' ? Number(bulkStock) : v.stock
      }));
      onUpdate('variants', newVariants);
  };

  const handleVariantChange = (idx: number, field: string, val: any) => {
      const newVariants = [...editData.variants];
      newVariants[idx] = { ...newVariants[idx], [field]: val };
      onUpdate('variants', newVariants);
  };

  const handleAddImage = () => {
      if (editData.images.length >= 9) return alert("Tối đa 9 ảnh");
      const url = prompt("Nhập URL hình ảnh:");
      if (url) onUpdate('images', [...editData.images, url]);
  };

  const handleRemoveImage = (idx: number) => {
      const newImgs = editData.images.filter((_, i) => i !== idx);
      onUpdate('images', newImgs);
  };

  const handleAddAttribute = () => {
      const newAttrs = [...editData.attributes, { name: '', value: '' }];
      onUpdate('attributes', newAttrs);
  };

  const handleAttrChange = (idx: number, key: 'name' | 'value', val: string) => {
      const newAttrs = [...editData.attributes];
      newAttrs[idx][key] = val;
      onUpdate('attributes', newAttrs);
  };

  const handleRemoveAttr = (idx: number) => {
      const newAttrs = editData.attributes.filter((_, i) => i !== idx);
      onUpdate('attributes', newAttrs);
  };

  const toggleShipping = (channel: string) => {
      const current = editData.shipping;
      if (current.includes(channel)) {
          onUpdate('shipping', current.filter(c => c !== channel));
      } else {
          onUpdate('shipping', [...current, channel]);
      }
  };

  return (
      <div className="h-full flex flex-col animate-fade-in bg-slate-50">
          <div className="flex items-center gap-3 p-4 border-b border-slate-100 bg-white sticky top-0 z-20 shadow-sm">
              <div className="flex-1">
                  <h4 className="font-bold text-slate-800 text-lg">Chi tiết đăng bán</h4>
                  <p className="text-xs text-slate-500">Hoàn tất thông tin để đẩy lên {selectedShopsCount} shop</p>
              </div>
              <button 
                  onClick={onPublish}
                  className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl text-sm font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-200 flex items-center gap-2"
              >
                  <Rocket size={18} /> Đăng ngay
              </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-6">
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                  {/* Left Column: General Info & Variants (2/3 width) */}
                  <div className="space-y-6 lg:col-span-2">
                      {/* Basic Info Inputs */}
                      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 space-y-4">
                          <h5 className="font-bold text-slate-800 flex items-center gap-2 border-b pb-2"><Info size={18} className="text-indigo-600"/> Thông tin chung</h5>
                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tên sản phẩm</label>
                              <input type="text" value={editData.name} onChange={e => onUpdate('name', e.target.value)} className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none font-medium"/>
                          </div>
                          <div className="grid grid-cols-2 gap-3">
                              <div>
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Mã SKU</label>
                                  <input type="text" value={editData.sku} onChange={e => onUpdate('sku', e.target.value)} className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm font-mono"/>
                              </div>
                              <div>
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Danh mục</label>
                                  <input type="text" value={editData.category} onChange={e => onUpdate('category', e.target.value)} className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm"/>
                              </div>
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Mô tả sản phẩm</label>
                              <textarea rows={6} value={editData.description} onChange={e => onUpdate('description', e.target.value)} className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none"/>
                          </div>
                      </div>

                      {/* Attributes */}
                      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 space-y-4">
                          <div className="flex justify-between items-center border-b pb-2">
                              <h5 className="font-bold text-slate-800 flex items-center gap-2"><Tag size={18} className="text-indigo-600"/> Thuộc tính sản phẩm</h5>
                              <button onClick={handleAddAttribute} className="text-xs font-bold text-indigo-600 hover:bg-indigo-50 px-2 py-1 rounded">+ Thêm thuộc tính</button>
                          </div>

                          <div className="space-y-3">
                              {editData.attributes.map((attr, idx) => (
                                  <div key={idx} className="flex gap-3 items-center">
                                      <div className="w-1/3">
                                          <input 
                                            type="text" 
                                            placeholder="Tên thuộc tính" 
                                            value={attr.name} 
                                            onChange={e => handleAttrChange(idx, 'name', e.target.value)} 
                                            className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-xs font-bold text-slate-700"
                                          />
                                      </div>
                                      <div className="flex-1">
                                          <input 
                                            type="text" 
                                            placeholder="Giá trị" 
                                            value={attr.value} 
                                            onChange={e => handleAttrChange(idx, 'value', e.target.value)} 
                                            className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                                          />
                                      </div>
                                      <button onClick={() => handleRemoveAttr(idx)} className="text-slate-400 hover:text-red-500 p-1"><Trash2 size={16}/></button>
                                  </div>
                              ))}
                          </div>
                      </div>

                      {/* Variants (Enhanced Redesign) */}
                      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 space-y-4">
                          <div className="flex justify-between items-center border-b pb-2">
                              <h5 className="font-bold text-slate-800 flex items-center gap-2"><Layers size={18} className="text-indigo-600"/> Phân loại hàng (Biến thể)</h5>
                          </div>

                          {/* Creation Controls */}
                          <div className="space-y-4 bg-slate-50 p-4 rounded-xl border border-slate-100">
                              {/* Group 1 */}
                              <div>
                                  <div className="flex gap-2 mb-2 items-center">
                                      <label className="text-xs font-bold text-slate-500 uppercase">Nhóm 1:</label>
                                      <input type="text" value={variantGroup1.name} onChange={(e) => setVariantGroup1({...variantGroup1, name: e.target.value})} className="px-2 py-1 text-sm font-bold border rounded w-32" />
                                  </div>
                                  <div className="flex flex-wrap gap-2">
                                      {variantGroup1.values.map(val => (
                                          <span key={val} className="bg-white border px-2 py-1 rounded text-xs flex items-center gap-1 font-medium">{val} <button onClick={() => handleRemoveVariantValue(1, val)}><X size={10}/></button></span>
                                      ))}
                                      <div className="flex gap-1">
                                          <input type="text" value={tempVal1} onChange={(e) => setTempVal1(e.target.value)} className="w-20 px-2 py-1 text-xs border rounded" placeholder="Giá trị..." onKeyDown={(e) => e.key === 'Enter' && handleAddVariantValue(1)} />
                                          <button onClick={() => handleAddVariantValue(1)} className="bg-indigo-600 text-white px-2 rounded"><Plus size={14}/></button>
                                      </div>
                                  </div>
                              </div>
                              {/* Group 2 */}
                              <div>
                                  <div className="flex gap-2 mb-2 items-center">
                                      <label className="text-xs font-bold text-slate-500 uppercase">Nhóm 2:</label>
                                      <input type="text" value={variantGroup2.name} onChange={(e) => setVariantGroup2({...variantGroup2, name: e.target.value})} className="px-2 py-1 text-sm font-bold border rounded w-32" />
                                  </div>
                                  <div className="flex flex-wrap gap-2">
                                      {variantGroup2.values.map(val => (
                                          <span key={val} className="bg-white border px-2 py-1 rounded text-xs flex items-center gap-1 font-medium">{val} <button onClick={() => handleRemoveVariantValue(2, val)}><X size={10}/></button></span>
                                      ))}
                                      <div className="flex gap-1">
                                          <input type="text" value={tempVal2} onChange={(e) => setTempVal2(e.target.value)} className="w-20 px-2 py-1 text-xs border rounded" placeholder="Giá trị..." onKeyDown={(e) => e.key === 'Enter' && handleAddVariantValue(2)}/>
                                          <button onClick={() => handleAddVariantValue(2)} className="bg-indigo-600 text-white px-2 rounded"><Plus size={14}/></button>
                                      </div>
                                  </div>
                              </div>

                              {/* Bulk Edit */}
                              <div className="flex items-center gap-2 pt-2 border-t border-slate-200">
                                  <span className="text-xs font-bold text-indigo-600">Áp dụng hàng loạt:</span>
                                  <input type="number" placeholder="Giá" value={bulkPrice} onChange={e => setBulkPrice(e.target.value === '' ? '' : Number(e.target.value))} className="w-24 px-2 py-1 text-xs border rounded" />
                                  <input type="number" placeholder="Kho" value={bulkStock} onChange={e => setBulkStock(e.target.value === '' ? '' : Number(e.target.value))} className="w-16 px-2 py-1 text-xs border rounded" />
                                  <button onClick={applyBulkVariant} className="text-xs bg-indigo-100 text-indigo-700 px-3 py-1.5 rounded font-bold hover:bg-indigo-200">Áp dụng</button>
                              </div>
                          </div>

                          {/* Table */}
                          {editData.variants.length > 0 ? (
                              <div className="border border-slate-200 rounded-lg overflow-hidden">
                                  <table className="w-full text-sm text-left">
                                      <thead className="bg-slate-100 text-slate-600 font-semibold text-xs uppercase">
                                          <tr>
                                              <th className="px-3 py-2 w-12 text-center">Ảnh</th>
                                              <th className="px-3 py-2">Phân loại</th>
                                              <th className="px-3 py-2 w-32">SKU</th>
                                              <th className="px-3 py-2 w-28 text-right">Giá</th>
                                              <th className="px-3 py-2 w-20 text-center">Kho</th>
                                          </tr>
                                      </thead>
                                      <tbody className="divide-y divide-slate-100">
                                          {editData.variants.map((v: any, idx: number) => (
                                              <tr key={v.id} className="hover:bg-slate-50">
                                                  <td className="px-3 py-2 text-center">
                                                      <div className="w-8 h-8 bg-white border rounded flex items-center justify-center cursor-pointer hover:border-indigo-400 mx-auto" onClick={() => { const u = prompt("URL ảnh biến thể:"); if(u) handleVariantChange(idx, 'image', u); }}>
                                                          {v.image ? <img src={v.image} className="w-full h-full object-cover rounded"/> : <Camera size={14} className="text-slate-300"/>}
                                                      </div>
                                                  </td>
                                                  <td className="px-3 py-2 font-bold text-slate-700">{v.name}</td>
                                                  <td className="px-3 py-2">
                                                      <input 
                                                        type="text" 
                                                        value={v.sku} 
                                                        onChange={e => handleVariantChange(idx, 'sku', e.target.value)} 
                                                        className="w-full bg-transparent border border-slate-200 rounded px-2 py-1 text-xs font-mono"
                                                      />
                                                  </td>
                                                  <td className="px-3 py-2 text-right">
                                                      <input type="number" value={v.price} onChange={e => handleVariantChange(idx, 'price', Number(e.target.value))} className="w-full border rounded px-2 py-1 text-xs font-bold text-indigo-600 text-right"/>
                                                  </td>
                                                  <td className="px-3 py-2 text-center">
                                                      <input type="number" value={v.stock} onChange={e => handleVariantChange(idx, 'stock', Number(e.target.value))} className="w-full border rounded px-2 py-1 text-xs text-center"/>
                                                  </td>
                                              </tr>
                                          ))}
                                      </tbody>
                                  </table>
                              </div>
                          ) : (
                              <div className="text-center text-slate-400 text-xs py-4">Chưa có biến thể nào được tạo.</div>
                          )}
                      </div>
                  </div>

                  {/* Right Column: Images, Price, Shipping (1/3 width) */}
                  <div className="space-y-6 lg:col-span-1">

                      {/* Media Gallery (Refined 9 images Grid) */}
                      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 space-y-4">
                          <h5 className="font-bold text-slate-800 flex items-center gap-2 border-b pb-2"><ImageIcon size={18} className="text-indigo-600"/> Hình ảnh & Video</h5>

                          <div className="grid grid-cols-3 gap-2">
                              {/* Loop 9 slots */}
                              {[...Array(9)].map((_, i) => {
                                  const img = i === 0 ? editData.image : editData.images[i-1];
                                  const isCover = i === 0;
                                  return (
                                      <div key={i} className={`aspect-square relative group bg-slate-50 rounded-lg border flex items-center justify-center overflow-hidden ${isCover ? 'border-indigo-400 ring-2 ring-indigo-100' : 'border-slate-200'}`}>
                                          {img ? (
