                  newVariants.push(existing || {
                      id: `v-${Date.now()}-${Math.random()}`,
                      name: name,
                      sku: `${editData.sku}-${v1.substring(0,3).toUpperCase()}`,
                      price: editData.price,
                      stock: 0,
                      image: ''
                  });
              }
          });
      }
      onUpdate('variants', newVariants);
  };

  const handleApplyBulkVariant = () => {
      const newVariants = editData.variants.map(v => ({
          ...v,
          price: bulkVariantPrice !== '' ? Number(bulkVariantPrice) : v.price,
          stock: bulkVariantStock !== '' ? Number(bulkVariantStock) : v.stock
      }));
      onUpdate('variants', newVariants);
  };

