          if (editData.attributes.length === 0) {
              editData.attributes = [
                  { name: 'Xuất xứ', value: '' },
                  { name: 'Loại thẻ', value: '' },
                  { name: 'Tên tổ chức chịu trách nhiệm sản xuất', value: '' },
