                  { name: 'Sản phẩm đặt theo yêu cầu', value: 'Không' }
              ];
          }

          return (
            <ListingStep4 
              editData={editData} 
              onUpdate={(field, value) => handleListingEditChange(productId, field, value)}
              onPublish={handlePublishListing}
              selectedShopsCount={listingSelectedShops.length}
            />
          );
      }

      return (
          <div className="h-full flex flex-col bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-fade-in">
              {!editingListingDetailId && (
                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-50">
