                          <span>Chi tiết</span>
                      </div>
                  </div>
              )}

              <div className="flex-1 p-6 overflow-hidden">
                  {listingStep === 1 && renderStep1()}
                  {listingStep === 2 && renderStep2()}
                  {listingStep === 3 && renderStep3()}
