                  {/* Left Column (2/3) */}
                  <div className="lg:col-span-2 space-y-6">
                      {/* 1. General Info */}
                      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                          <h3 className="font-bold text-lg text-slate-800 mb-6 flex items-center gap-2">
                              <Box className="text-indigo-600" size={20} /> Thông tin chung
                          </h3>
                          <div className="space-y-5">
                              <div>
                                  <label className="block text-sm font-semibold text-slate-700 mb-1">Tên sản phẩm <span className="text-red-500">*</span></label>
                                  <input 
                                      type="text" 
                                      value={editData.name}
                                      onChange={e => onUpdate('name', e.target.value)}
                                      className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                                      placeholder="VD: Áo Thun Nam Cotton Cao Cấp..."
                                  />
                              </div>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                  <div>
                                      <label className="block text-sm font-semibold text-slate-700 mb-1">Mã SKU</label>
                                      <input 
                                          type="text" 
                                          value={editData.sku}
                                          onChange={e => onUpdate('sku', e.target.value)}
                                          className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                      />
                                  </div>
