const getCategoryForShop = (shopName: string): keyof typeof PRODUCT_CATEGORIES => {
  const lowerName = shopName.toLowerCase();
  if (lowerName.includes('tech') || lowerName.includes('điện')) return 'tech';
  if (lowerName.includes('mỹ phẩm') || lowerName.includes('beauty')) return 'beauty';
  if (lowerName.includes('gia dụng') || lowerName.includes('nhà') || lowerName.includes('decor')) return 'home';
  if (lowerName.includes('ăn') || lowerName.includes('snack')) return 'food';
  return 'fashion'; // Default
};

const generateExternalProducts = (): ExternalProduct[] => {
  let allProducts: ExternalProduct[] = [];

  INITIAL_INTEGRATIONS.forEach(integration => {
    integration.shops.forEach(shop => {
      const categoryKey = getCategoryForShop(shop.name);
      const category = PRODUCT_CATEGORIES[categoryKey];
      // Generate 30-50 products per shop
      const productCount = Math.floor(Math.random() * 21) + 30; 

      for (let i = 0; i < productCount; i++) {
        const randomName = category.names[Math.floor(Math.random() * category.names.length)];
        const suffix = Math.floor(Math.random() * 1000);
        const price = Math.floor(Math.random() * (category.priceRange[1] - category.priceRange[0])) + category.priceRange[0];
        // Round price to nearest 1000
        const roundedPrice = Math.round(price / 1000) * 1000;

        const randomImageKeyword = category.images[Math.floor(Math.random() * category.images.length)];

        // Random sync status: 70% synced, 20% unsynced, 10% error
        const randStatus = Math.random();
        let syncStatus: 'synced' | 'unsynced' | 'error' = 'synced';
        let errorMsg = undefined;
        let linkedId = undefined;

        if (randStatus > 0.9) {
           syncStatus = 'error';
           errorMsg = 'SKU không tồn tại trong hệ thống';
        } else if (randStatus > 0.7) {
           syncStatus = 'unsynced';
        } else {
           linkedId = `P${Math.floor(Math.random() * 100) + 100}`;
        }

        allProducts.push({
          id: `${shop.id}_p${i}`,
          platform: integration.platform,
          shopId: shop.id,
          shopName: shop.name,
          externalId: `${integration.platform.substring(0,2).toUpperCase()}_${Date.now()}_${i}`,
          name: `${randomName} - Mẫu ${suffix}`,
          sku: `${categoryKey.toUpperCase()}-${shop.id.toUpperCase()}-${i}`,
          price: roundedPrice,
          stock: Math.floor(Math.random() * 200),
          image: `https://loremflickr.com/200/200/${randomImageKeyword}?random=${shop.id}${i}`,
          syncStatus: syncStatus,
          linkedProductId: linkedId,
          lastSyncAt: new Date(Date.now() - Math.floor(Math.random() * 100000000)).toLocaleString('vi-VN'),
          errorMsg: errorMsg
        });
      }
    });
  });

  return allProducts;
};

