// Define Interface for Source Product in Import Tool
interface SourceProduct {
    id: string;
    name: string;
    sku: string;
    price: number;
    stock: number;
    image: string;
    weight: number;
    description: string;
    status: 'active' | 'inactive';
    existsInOmni: boolean; // Is SKU already in OmniSales?
    isCopied: boolean; // Has been copied in this session?
    variantsCount: number; // Added: Number of variants
}

// Define Interface for Sync History
interface SyncHistoryItem {
    id: string;
    sourceShopName: string;
    targetCount: number;
    timestamp: string;
    status: 'success' | 'failed' | 'partial';
    productsSynced: number;
}

// Define Interface for Import History
interface ImportHistoryItem {
    id: string;
    sourceShopName: string;
    targetWarehouseName: string;
    productCount: number;
    timestamp: string;
    status: 'success' | 'failed';
    details: SourceProduct[]; // Added details to history
}

interface ListingEditData {
    name: string;
    sku: string;
    price: number;
    stock: number;
    description: string;
    weight: number;
    length: number;
    width: number;
    height: number;
    category: string;
    image: string;
    images: string[];
    video: string;
    videoType: 'link' | 'upload';
    attributes: { name: string; value: string }[];
    variants: any[];
    shipping: string[];
    // Add missing fields for compat with ProductList logic
    importPrice?: number;
    salePrice?: number;
    barcode?: string;
    status: 'active' | 'draft' | 'inactive';
}

// --- REDESIGNED LISTING STEP 4 ---
const ListingStep4: React.FC<{
  editData: ListingEditData;
  onUpdate: (field: string, value: any) => void;
  onPublish: () => void;
  onBack: () => void;
  selectedShopsCount: number;
}> = ({ editData, onUpdate, onPublish, onBack, selectedShopsCount }) => {
  // Local State for Variant Logic
  const [hasVariants, setHasVariants] = useState(editData.variants && editData.variants.length > 0);
  const [variantGroup1, setVariantGroup1] = useState({ name: 'Màu sắc', values: [] as string[] });
  const [variantGroup2, setVariantGroup2] = useState({ name: 'Kích thước', values: [] as string[] });
  const [tempValue1, setTempValue1] = useState('');
  const [tempValue2, setTempValue2] = useState('');

  // Bulk Edit State
  const [bulkVariantPrice, setBulkVariantPrice] = useState<number | ''>('');
  const [bulkVariantStock, setBulkVariantStock] = useState<number | ''>('');

  // AI & Video
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [aiKeywords, setAiKeywords] = useState('');
  const [videoMode, setVideoMode] = useState<'link' | 'upload'>('link');

  // Category Dropdown
  const [isCategoryDropdownOpen, setIsCategoryDropdownOpen] = useState(false);
  const filteredCategories = MOCK_CATEGORIES.filter(c => c.toLowerCase().includes((editData.category || '').toLowerCase()));

  // -- Variant Logic --
  const addVariantValue = (group: 1 | 2) => {
      if (group === 1) {
          if (!tempValue1.trim()) return;
          if (variantGroup1.values.includes(tempValue1.trim())) return;
          const newValues = [...variantGroup1.values, tempValue1.trim()];
          setVariantGroup1({ ...variantGroup1, values: newValues });
          setTempValue1('');
          regenerateVariants(newValues, variantGroup2.values);
      } else {
          if (!tempValue2.trim()) return;
          if (variantGroup2.values.includes(tempValue2.trim())) return;
          const newValues = [...variantGroup2.values, tempValue2.trim()];
          setVariantGroup2({ ...variantGroup2, values: newValues });
          setTempValue2('');
          regenerateVariants(variantGroup1.values, newValues);
      }
  };

  const removeVariantValue = (group: 1 | 2, value: string) => {
      if (group === 1) {
          const newValues = variantGroup1.values.filter(v => v !== value);
          setVariantGroup1({ ...variantGroup1, values: newValues });
          regenerateVariants(newValues, variantGroup2.values);
      } else {
          const newValues = variantGroup2.values.filter(v => v !== value);
          setVariantGroup2({ ...variantGroup2, values: newValues });
          regenerateVariants(variantGroup1.values, newValues);
      }
  };

  const regenerateVariants = (vals1: string[], vals2: string[]) => {
      const newVariants: any[] = [];

      if (vals1.length > 0) {
          vals1.forEach(v1 => {
              if (vals2.length > 0) {
                  vals2.forEach(v2 => {
                      const name = `${v1} - ${v2}`;
                      const existing = editData.variants?.find((v: any) => v.name === name);
                      newVariants.push(existing || {
                          id: `v-${Date.now()}-${Math.random()}`,
                          name: name,
                          sku: `${editData.sku}-${v1.substring(0,3).toUpperCase()}-${v2.substring(0,3).toUpperCase()}`,
                          price: editData.price,
                          stock: 0,
                          image: ''
                      });
                  });
              } else {
                  const name = v1;
                  const existing = editData.variants?.find((v: any) => v.name === name);
                  newVariants.push(existing || {
                      id: `v-${Date.now()}-${Math.random()}`,
                      name: name,
                      sku: `${editData.sku}-${v1.substring(0,3).toUpperCase()}`,
                      price: editData.price,
                      stock: 0,
                      image: ''
                  });
              }
          });
      }
      onUpdate('variants', newVariants);
  };

  const handleApplyBulkVariant = () => {
      const newVariants = editData.variants.map(v => ({
          ...v,
          price: bulkVariantPrice !== '' ? Number(bulkVariantPrice) : v.price,
          stock: bulkVariantStock !== '' ? Number(bulkVariantStock) : v.stock
      }));
      onUpdate('variants', newVariants);
  };

  const updateVariantField = (idx: number, field: string, value: any) => {
      const newVariants = [...editData.variants];
      newVariants[idx] = { ...newVariants[idx], [field]: value };
      onUpdate('variants', newVariants);
  };

  const handleGenerateDescription = async () => {
      if (!editData.name || !editData.category) {
          alert("Vui lòng nhập tên và danh mục trước khi dùng AI.");
          return;
      }
      setIsGeneratingAi(true);
      const desc = await generateProductDescription(editData.name, editData.category, aiKeywords || editData.name);
      if (desc) onUpdate('description', desc);
      setIsGeneratingAi(false);
  };

  const handleAttributeChange = (name: string, value: string) => {
      const newAttrs = [...(editData.attributes || [])];
      const idx = newAttrs.findIndex(a => a.name === name);
      if (idx > -1) {
          newAttrs[idx].value = value;
      } else {
          newAttrs.push({ name, value });
      }
      onUpdate('attributes', newAttrs);
  };

  const getAttributeValue = (name: string) => {
      return editData.attributes?.find(a => a.name === name)?.value || '';
  };

  const toggleShipping = (channel: string) => {
      const current = editData.shipping || [];
      if (current.includes(channel)) {
          onUpdate('shipping', current.filter(c => c !== channel));
      } else {
          onUpdate('shipping', [...current, channel]);
      }
  };

  // Image Handlers
  const addImageToGallery = () => {
      if (editData.images.length >= 9) return alert("Tối đa 9 ảnh.");
      const url = prompt("Nhập URL hình ảnh (Demo):", `https://loremflickr.com/300/300/product?random=${Date.now()}`);
      if (url) onUpdate('images', [...editData.images, url]);
  };

  const removeImageFromGallery = (idx: number) => {
      onUpdate('images', editData.images.filter((_, i) => i !== idx));
  };

  return (
      <div className="bg-slate-50 min-h-full flex flex-col animate-fade-in relative">
          {/* Header */}
          <div className="sticky top-0 z-20 bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shadow-sm">
              <div className="flex items-center gap-4">
                  <button 
                    onClick={onBack}
                    className="flex items-center gap-2 px-4 py-2 bg-white border border-indigo-200 text-indigo-600 rounded-xl text-sm font-bold shadow-sm hover:bg-indigo-50 transition-all"
                    title="Quay lại bước 3"
                  >
                    <ArrowLeft size={18} /> Quay lại
                  </button>
                  <div>
                    <h2 className="text-xl font-bold text-slate-800">Chi tiết đăng bán</h2>
                    <p className="text-xs text-slate-500">Hoàn tất thông tin để đẩy lên {selectedShopsCount} shop</p>
                  </div>
              </div>
              <button 
                  onClick={onPublish}
                  className="px-5 py-2.5 bg-indigo-600 text-white hover:bg-indigo-700 rounded-xl text-sm font-bold flex items-center gap-2 transition-colors shadow-lg shadow-indigo-200"
              >
                  <Rocket size={18} /> Đăng ngay
              </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6">
              <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6">

                  {/* Left Column (2/3) */}
                  <div className="lg:col-span-2 space-y-6">
                      {/* 1. General Info */}
                      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                          <h3 className="font-bold text-lg text-slate-800 mb-6 flex items-center gap-2">
                              <Box className="text-indigo-600" size={20} /> Thông tin chung
                          </h3>
                          <div className="space-y-5">
                              <div>
                                  <label className="block text-sm font-semibold text-slate-700 mb-1">Tên sản phẩm <span className="text-red-500">*</span></label>
                                  <input 
                                      type="text" 
                                      value={editData.name}
                                      onChange={e => onUpdate('name', e.target.value)}
                                      className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                                      placeholder="VD: Áo Thun Nam Cotton Cao Cấp..."
                                  />
                              </div>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                  <div>
                                      <label className="block text-sm font-semibold text-slate-700 mb-1">Mã SKU</label>
                                      <input 
                                          type="text" 
                                          value={editData.sku}
                                          onChange={e => onUpdate('sku', e.target.value)}
                                          className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                      />
                                  </div>
                                  <div>
                                      <label className="block text-sm font-semibold text-slate-700 mb-1 flex items-center gap-1">
                                          <Barcode size={16} className="text-slate-500" /> Mã vạch
                                      </label>
                                      <input 
                                          type="text" 
                                          value={editData.barcode || ''}
                                          onChange={e => onUpdate('barcode', e.target.value)}
                                          className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 font-mono"
                                      />
                                  </div>
                              </div>
                              <div className="relative">
                                  <label className="block text-sm font-semibold text-slate-700 mb-1 flex items-center gap-1">
                                      <List size={16} className="text-slate-500" /> Danh mục ngành hàng
                                  </label>
                                  <input 
                                      type="text" 
                                      value={editData.category}
                                      onChange={e => { onUpdate('category', e.target.value); setIsCategoryDropdownOpen(true); }}
                                      onFocus={() => setIsCategoryDropdownOpen(true)}
                                      onBlur={() => setTimeout(() => setIsCategoryDropdownOpen(false), 200)}
                                      className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                                      placeholder="Chọn hoặc nhập mới..."
                                  />
                                  {isCategoryDropdownOpen && (
                                      <div className="absolute z-10 w-full mt-1 bg-white border border-slate-200 rounded-xl shadow-xl max-h-48 overflow-y-auto">
                                          {filteredCategories.map((cat, idx) => (
                                              <div 
                                                  key={idx} 
                                                  className="px-4 py-2.5 hover:bg-indigo-50 cursor-pointer text-sm text-slate-700"
                                                  onClick={() => onUpdate('category', cat)}
                                              >
                                                  {cat}
                                              </div>
                                          ))}
                                      </div>
                                  )}
                              </div>
                          </div>
                      </div>

                      {/* 2. Platform Required Info (NEW BLOCK) */}
                      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                          <h3 className="font-bold text-lg text-slate-800 mb-6 flex items-center gap-2">
                              <ClipboardCheck className="text-indigo-600" size={20} /> Thông tin bắt buộc theo sàn
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                              <div>
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Xuất xứ</label>
                                  <input 
                                    type="text" 
                                    value={getAttributeValue('Xuất xứ')} 
                                    onChange={e => handleAttributeChange('Xuất xứ', e.target.value)}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500"
                                    placeholder="VD: Việt Nam"
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Loại thẻ</label>
                                  <input 
                                    type="text" 
                                    value={getAttributeValue('Loại thẻ')} 
                                    onChange={e => handleAttributeChange('Loại thẻ', e.target.value)}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500"
                                    placeholder="VD: Thẻ giấy"
                                  />
                              </div>
                              <div className="md:col-span-2">
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tên tổ chức chịu trách nhiệm sản xuất</label>
                                  <input 
                                    type="text" 
                                    value={getAttributeValue('Tên tổ chức chịu trách nhiệm sản xuất')} 
                                    onChange={e => handleAttributeChange('Tên tổ chức chịu trách nhiệm sản xuất', e.target.value)}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500"
                                    placeholder="VD: Công ty TNHH Sản Xuất ABC"
                                  />
                              </div>
                              <div className="md:col-span-2">
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Địa chỉ tổ chức chịu trách nhiệm sản xuất</label>
                                  <input 
                                    type="text" 
                                    value={getAttributeValue('Địa chỉ tổ chức chịu trách nhiệm sản xuất')} 
                                    onChange={e => handleAttributeChange('Địa chỉ tổ chức chịu trách nhiệm sản xuất', e.target.value)}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500"
                                    placeholder="VD: 123 Đường Láng, Hà Nội"
                                  />
                              </div>
                              <div className="md:col-span-2">
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Sản phẩm đặt theo yêu cầu</label>
                                  <select 
                                    value={getAttributeValue('Sản phẩm đặt theo yêu cầu')} 
                                    onChange={e => handleAttributeChange('Sản phẩm đặt theo yêu cầu', e.target.value)}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-indigo-500"
                                  >
                                      <option value="Không">Không</option>
                                      <option value="Có">Có (Hàng đặt trước)</option>
                                  </select>
                              </div>
                          </div>
                      </div>

                      {/* 3. Description (AI) */}
                      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 relative overflow-hidden">
                          <div className="flex justify-between items-center mb-4">
                              <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2"><Edit3 size={20} className="text-indigo-600" /> Mô tả chi tiết</h3>
                              <span className="text-xs text-slate-400 font-medium">{(editData.description || '').length} ký tự</span>
                          </div>

                          <div className="bg-indigo-50 rounded-xl p-3 mb-4 flex flex-col sm:flex-row gap-3 items-center border border-indigo-100">
                              <div className="p-2 bg-white rounded-lg text-indigo-600 shadow-sm"><Sparkles size={18} /></div>
                              <input type="text" placeholder="Nhập từ khóa (VD: vải mát, co giãn)..." value={aiKeywords} onChange={e => setAiKeywords(e.target.value)} className="flex-1 w-full bg-white border-0 rounded-lg px-3 py-1.5 text-sm focus:ring-2 focus:ring-indigo-300"/>
                              <button onClick={handleGenerateDescription} disabled={isGeneratingAi} className="px-4 py-2 bg-indigo-600 text-white text-xs font-bold rounded-lg hover:bg-indigo-700 transition-colors disabled:opacity-70 flex items-center gap-2">{isGeneratingAi ? <Loader2 className="animate-spin" size={14}/> : 'Viết với AI'}</button>
                          </div>

                          <textarea rows={8} value={editData.description} onChange={e => onUpdate('description', e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none text-sm leading-relaxed" placeholder="Mô tả chi tiết sản phẩm..."/>
