                                      className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500"
                                  />
                                  <span className="text-sm font-medium text-slate-700">Sản phẩm có biến thể</span>
                              </label>
                          </div>

                          {hasVariants && (
                              <div className="animate-fade-in space-y-6">
                                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-50 p-4 rounded-xl border border-slate-200">
                                      {/* Group 1 */}
                                      <div>
                                          <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Nhóm 1 (Ví dụ: Màu sắc)</label>
                                          <input type="text" value={variantGroup1.name} onChange={e => setVariantGroup1({...variantGroup1, name: e.target.value})} className="w-full px-3 py-2 border rounded-lg text-sm mb-3 font-bold text-slate-700" />
                                          <div className="flex flex-wrap gap-2 mb-2">
                                              {variantGroup1.values.map(val => (
                                                  <span key={val} className="bg-white border px-2 py-1 rounded text-sm flex items-center gap-1">
                                                      {val} <button onClick={() => removeVariantValue(1, val)}><X size={12}/></button>
                                                  </span>
                                              ))}
                                          </div>
                                          <div className="flex gap-2">
                                              <input 
                                                  type="text" 
                                                  value={tempValue1} 
                                                  onChange={e => setTempValue1(e.target.value)} 
                                                  onKeyDown={e => e.key === 'Enter' && addVariantValue(1)}
