          <div className="fixed inset-0 bg-black/50 z-[90] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in" onClick={() => setSelectedHistoryItem(null)}>
              <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                      <h3 className="font-bold text-lg text-slate-800">Chi tiết phiên sao chép</h3>
                      <button onClick={() => setSelectedHistoryItem(null)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                  </div>
                  <div className="p-4 bg-white border-b border-slate-100 grid grid-cols-2 gap-4 text-sm">
                      <div><span className="text-slate-500">Thời gian:</span> <span className="font-bold">{selectedHistoryItem.timestamp}</span></div>
                      <div><span className="text-slate-500">Số lượng:</span> <span className="font-bold">{selectedHistoryItem.productCount} SP</span></div>
                      <div><span className="text-slate-500">Từ:</span> <span className="font-bold">{selectedHistoryItem.sourceShopName}</span></div>
                      <div><span className="text-slate-500">Đến:</span> <span className="font-bold">{selectedHistoryItem.targetWarehouseName}</span></div>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <table className="w-full text-sm text-left">
                          <thead className="bg-slate-50 text-slate-500 font-semibold sticky top-0">
                              <tr>
                                  <th className="px-3 py-2">Sản phẩm</th>
                                  <th className="px-3 py-2">SKU</th>
                                  <th className="px-3 py-2 text-right">Giá</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                              {selectedHistoryItem.details?.map((p, idx) => (
                                  <tr key={idx} className="hover:bg-slate-50">
                                      <td className="px-3 py-2 flex items-center gap-2">
                                          <img src={p.image} className="w-8 h-8 rounded border border-slate-200 object-cover"/>
                                          <span className="truncate max-w-[200px]">{p.name}</span>
                                      </td>
                                      <td className="px-3 py-2 text-slate-500 font-mono text-xs">{p.sku}</td>
                                      <td className="px-3 py-2 text-right font-medium">{formatCurrency(p.price)}</td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>
          </div>
      );
  };

  const renderPriceHistoryModal = () => {
      if (!selectedPriceHistoryItem) return null;
      const h = selectedPriceHistoryItem;
      return (
          <div className="fixed inset-0 bg-black/50 z-[90] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in" onClick={() => setSelectedPriceHistoryItem(null)}>
              <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                      <h3 className="font-bold text-lg text-slate-800">Chi tiết thay đổi giá</h3>
                      <button onClick={() => setSelectedPriceHistoryItem(null)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                  </div>
                  <div className="p-4 bg-white border-b border-slate-100 text-sm">
                      <div className="flex gap-4 mb-2">
                          <span className="text-slate-500">Hành động:</span> <span className="font-bold text-indigo-600">{h.action}</span>
                      </div>
                      <div className="flex gap-4">
                          <span className="text-slate-500">Thời gian:</span> <span className="font-bold">{h.time}</span>
                          <span className="text-slate-500 ml-4">Người thực hiện:</span> <span className="font-bold">{h.user}</span>
                      </div>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <table className="w-full text-sm text-left">
                          <thead className="bg-slate-50 text-slate-500 font-semibold sticky top-0">
                              <tr>
                                  <th className="px-3 py-2">Sản phẩm</th>
                                  <th className="px-3 py-2 text-right">Giá cũ</th>
                                  <th className="px-3 py-2 text-center"><ArrowRight size={14}/></th>
                                  <th className="px-3 py-2 text-right">Giá mới</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                              {h.details?.map((p: any, idx: number) => (
                                  <tr key={idx} className="hover:bg-slate-50">
                                      <td className="px-3 py-2 flex items-center gap-2">
                                          <img src={p.image} className="w-8 h-8 rounded border border-slate-200 object-cover"/>
                                          <span className="truncate max-w-[200px]">{p.name}</span>
                                      </td>
                                      <td className="px-3 py-2 text-right text-slate-500 line-through">{formatCurrency(p.oldPrice)}</td>
                                      <td className="px-3 py-2 text-center text-slate-400"><ArrowRight size={12} className="mx-auto"/></td>
                                      <td className="px-3 py-2 text-right font-bold text-slate-800">{formatCurrency(p.newPrice)}</td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>
          </div>
      );
  };

  const renderPublishProgressModal = () => {
      if (!isPublishing) return null;
      return (
          <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-sm overflow-hidden flex flex-col items-center p-8 text-center relative">
                  <div className={`absolute top-0 left-0 w-full h-2 ${publishStatus === 'processing' ? 'bg-indigo-100' : 'bg-green-100'}`}>
                      <div className={`h-full transition-all duration-300 ease-out ${publishStatus === 'processing' ? 'bg-indigo-600' : 'bg-green-500'}`} style={{ width: `${publishProgress}%` }}></div>
                  </div>
                  {publishStatus === 'processing' ? (
                      <>
                          <div className="relative w-20 h-20 mb-6 mt-4">
                              <Loader2 size={80} className="animate-spin text-indigo-100" />
                              <div className="absolute inset-0 flex items-center justify-center text-sm font-bold text-indigo-600">{publishProgress}%</div>
                          </div>
                          <h3 className="text-xl font-bold text-slate-800 mb-2">Đang đăng bán...</h3>
                          <p className="text-slate-500 text-sm">Hệ thống đang đẩy sản phẩm lên các sàn đã chọn.</p>
                      </>
                  ) : (
                      <>
                          <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 mt-4 animate-bounce">
                              <CheckCircle2 size={40} strokeWidth={3} />
                          </div>
                          <h3 className="text-xl font-bold text-slate-800 mb-2">Đăng bán thành công!</h3>
                          <p className="text-slate-500 text-sm mb-6">Sản phẩm đã được đăng lên các sàn. Có thể mất vài phút để hiển thị.</p>
                          <button onClick={() => { setIsPublishing(false); setIsListingModalOpen(false); }} className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all shadow-lg">Hoàn tất</button>
                      </>
                  )}
              </div>
          </div>
      );
  };

  const renderSyncProgressModal = () => {
      if (!showSyncModal) return null;
      return (
          <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-sm overflow-hidden flex flex-col items-center p-8 text-center relative">
                  <div className="absolute top-0 left-0 w-full h-2 bg-indigo-100">
                      <div className="h-full bg-indigo-600 transition-all duration-100" style={{ width: `${syncProgress}%` }}></div>
                  </div>
                  {syncProgress < 100 ? (
                      <>
                          <div className="relative w-20 h-20 mb-6 mt-4">
                              <RefreshCw size={80} className="animate-spin text-indigo-100" />
                              <div className="absolute inset-0 flex items-center justify-center text-sm font-bold text-indigo-600">{syncProgress}%</div>
                          </div>
                          <h3 className="text-xl font-bold text-slate-800 mb-2">Đang đồng bộ...</h3>
                          <p className="text-slate-500 text-sm">Vui lòng không tắt trình duyệt.</p>
                      </>
                  ) : (
                      <>
                          <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 mt-4 animate-bounce">
                              <CheckCircle2 size={40} strokeWidth={3} />
                          </div>
                          <h3 className="text-xl font-bold text-slate-800 mb-2">Đồng bộ hoàn tất!</h3>
                          <p className="text-slate-500 text-sm mb-6">Dữ liệu đã được cập nhật thành công trên các shop đích.</p>
                          <button onClick={() => setShowSyncModal(false)} className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all shadow-lg">Đóng</button>
                      </>
                  )}
              </div>
          </div>
      );
  };

  return (
    <div className="pb-10">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Công cụ quản lý</h2>
        <p className="text-sm text-slate-500">Đồng bộ và quản lý dữ liệu sản phẩm trên diện rộng.</p>
      </div>

      {/* Navigation Tabs (Top) */}
      <div className="flex overflow-x-auto no-scrollbar gap-2 mb-6 bg-white p-2 rounded-xl border border-slate-100 shadow-sm">
        {tabs.map(tab => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.id;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                isActive 
                  ? 'bg-indigo-600 text-white shadow-md' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <Icon size={18} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Content Area */}
      <div>
         {activeTab === 'import' && renderProductImport()}
         {activeTab === 'listing' && (
            isListingModalOpen ? renderListingWizard() : renderListingTool()
         )}
         {activeTab === 'sync' && renderShopSync()}
         {activeTab === 'bulkedit' && renderBulkEdit()}
         {activeTab === 'keywords' && renderForbiddenKeywords()}
      </div>

      {/* Import Progress Modal */}
      {renderImportProgressModal()}

      {/* History Detail Modal */}
      {renderHistoryDetailModal()}

      {/* Price History Modal */}
      {renderPriceHistoryModal()}

      {/* Publish Progress Modal */}
      {renderPublishProgressModal()}

      {/* Sync Progress Modal */}
      {renderSyncProgressModal()}
    </div>
  );
};

export default Tools;
